return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var stage = 1;
    if (progress >= 0.33 && progress < 0.66) stage = 2;
    else if (progress >= 0.66) stage = 3;

    var midX = W / 2;
    var midY = H / 2 - 30;
    var cellSize = 22;
    var size = 3; // 3x3 square grid

    var startX = midX - (size * cellSize) / 2;
    var startY = midY - (size * cellSize) / 2;

    // Draw 3x3 grid
    for (var r = 0; r < size; r++) {
      for (var c = 0; c < size; c++) {
        var cx = startX + c * cellSize;
        var cy = startY + r * cellSize;

        ctx.fillStyle = '#1E3A8A'; // Dark blue background for cells
        ctx.fillRect(cx, cy, cellSize - 2, cellSize - 2);
        ctx.strokeStyle = '#3B82F6';
        ctx.lineWidth = 1;
        ctx.strokeRect(cx, cy, cellSize - 2, cellSize - 2);

        // Write block index
        ctx.fillStyle = '#9CA3AF';
        ctx.font = '8px monospace';
        ctx.textAlign = 'center';
        ctx.textBaseline = 'middle';
        ctx.fillText((r * size + c + 1).toString(), cx + cellSize/2 - 1, cy + cellSize/2 - 1);
      }
    }

    // Draw bottom border highlight in Stage 2 & 3
    if (stage >= 2) {
      ctx.strokeStyle = '#F59E0B'; // Gold line
      ctx.lineWidth = 3.5;
      ctx.beginPath();
      ctx.moveTo(startX, startY + size * cellSize - 1);
      ctx.lineTo(startX + size * cellSize, startY + size * cellSize - 1);
      ctx.stroke();

      // Draw brackets or tick marks
      ctx.beginPath();
      ctx.moveTo(startX, startY + size * cellSize - 5);
      ctx.lineTo(startX, startY + size * cellSize + 3);
      ctx.moveTo(startX + size * cellSize, startY + size * cellSize - 5);
      ctx.lineTo(startX + size * cellSize, startY + size * cellSize + 3);
      ctx.stroke();
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (stage === 1) {
      ctx.fillText('Area = 9 Blocks', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('We have a square composed of 9 unit square blocks.', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('Side Length = √9 = 3 Blocks', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('The square root asks: what side length creates an area of 9?', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#34D399';
      ctx.fillText('Inverse Relationship', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('Squaring: 3 → 9 (3²). Square Root: 9 → 3 (√9).', W / 2, H - 22);
    }
  }
};
